     * Generates a random session ID of the requested length.
     *
     * @param length desired session ID length (must be > 0)
     * @return session ID containing only [A-Za-z0-9]
     * @throws IllegalArgumentException if length is not positive
     * @throws IllegalStateException if a secure random value cannot be generated
     */
    public String generate(int length) {
        if (length <= 0) {
            throw new IllegalArgumentException("length must be positive");
        }

        try {
            char[] out = new char[length];
            for (int i = 0; i < length; i++) {
                out[i] = ALPHABET[SECURE_RANDOM.nextInt(ALPHABET.length)];
            }
            return new String(out);
        } catch (RuntimeException e) {
            // Defensive: SecureRandom#nextInt may throw in rare provider/entropy failure cases.
            throw new IllegalStateException("Failed to generate secure session ID", e);
        }
    }
}
